const css = `
.spt-shell {
  width: 100%;
  max-width: 100%;
  min-width: 0;
  overflow: hidden;
}


.spt-toolbar.route-visible {
  display: grid;
}

.spt-route-empty-card {
  min-height: min(360px, calc(100dvh - 28px));
  display: grid;
  place-items: center;
  align-content: center;
  gap: 10px;
  padding: 22px;
  border-radius: 28px;
  background: var(--card-bg, var(--surface, #fff));
  color: var(--text, #0f172a);
  border: 1px solid var(--border, rgba(148,163,184,.22));
  box-shadow: 0 18px 46px rgba(15,23,42,.07);
  text-align: center;
}

.spt-route-empty-icon {
  width: 58px;
  height: 58px;
  display: grid;
  place-items: center;
  border-radius: 22px;
  background: color-mix(in srgb, var(--spt-primary, var(--primary-color, #2563eb)) 12%, var(--surface, #fff));
  font-size: 28px;
}

.spt-route-empty-card h2 {
  margin: 0;
  color: var(--text, #0f172a);
  font-size: 22px;
  font-weight: 1000;
  letter-spacing: -.04em;
}

.spt-route-empty-card p {
  max-width: 34rem;
  margin: 0;
  color: var(--muted, #64748b);
  font-size: 13px;
  line-height: 1.6;
  font-weight: 750;
}

.spt-toolbar {
  display: none;
  grid-template-columns: auto minmax(0, 1fr) auto auto;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
  padding: 8px;
  border-radius: 24px;
  background: var(--card-bg, var(--surface, #fff));
  border: 1px solid var(--border, rgba(148,163,184,.22));
  box-shadow: 0 12px 28px rgba(15,23,42,.045);
}

.spt-status-dot {
  width: 10px;
  height: 10px;
  border-radius: 999px;
  display: inline-flex;
  box-shadow: 0 0 0 5px color-mix(in srgb, var(--spt-primary, var(--primary-color, #2563eb)) 12%, transparent);
}

.spt-status-dot.green {
  background: #22c55e;
}

.spt-status-dot.gray {
  background: var(--muted, #64748b);
}

.spt-toolbar-main {
  min-width: 0;
}

.spt-toolbar-main strong,
.spt-toolbar-main span {
  display: block;
  overflow: hidden;
  white-space: nowrap;
  text-overflow: ellipsis;
}

.spt-toolbar-main strong {
  color: var(--text, #0f172a);
  font-size: 13px;
  font-weight: 1000;
  letter-spacing: -.02em;
}

.spt-toolbar-main span {
  margin-top: 2px;
  color: var(--muted, #64748b);
  font-size: 11px;
  font-weight: 800;
}

.spt-toolbar-icon {
  width: 40px;
  height: 40px;
  display: grid;
  place-items: center;
  border: 1px solid var(--border, rgba(148,163,184,.22));
  border-radius: 999px;
  background: var(--card-bg, var(--surface, #fff));
  color: var(--text, #0f172a);
  font-size: 17px;
  font-weight: 1000;
  cursor: pointer;
  box-shadow: 0 10px 22px rgba(15,23,42,.045);
}

.spt-toolbar-icon.primary {
  border-color: var(--spt-primary, var(--primary-color, #2563eb));
  background: var(--spt-primary, var(--primary-color, #2563eb));
  color: #fff;
  box-shadow: 0 12px 28px color-mix(in srgb, var(--spt-primary, var(--primary-color, #2563eb)) 22%, transparent);
}

.spt-screen-chips {
  display: none;
  gap: 7px;
  overflow-x: auto;
  padding: 0 1px 8px;
  scrollbar-width: none;
}

.spt-screen-chips::-webkit-scrollbar {
  display: none;
}

.spt-screen-chips button {
  flex: 0 0 auto;
  min-height: 31px;
  border: 0;
  border-radius: 999px;
  padding: 0 10px;
  background: color-mix(in srgb, var(--spt-primary, var(--primary-color, #2563eb)) 11%, transparent);
  color: var(--spt-primary, var(--primary-color, #2563eb));
  font-size: 11px;
  font-weight: 950;
  white-space: nowrap;
  cursor: default;
}

.spt-sheet-backdrop {
  position: fixed;
  inset: 0;
  z-index: 80;
  display: grid;
  place-items: end center;
  padding: 10px;
  background: rgba(15,23,42,.50);
  backdrop-filter: blur(12px);
}

.spt-sheet {
  width: min(520px, 100%);
  max-height: min(88dvh, 760px);
  overflow-y: auto;
  padding: 14px;
  border-radius: 28px 28px 22px 22px;
  background: var(--card-bg, var(--surface, #fff));
  color: var(--text, #0f172a);
  border: 1px solid var(--border, rgba(148,163,184,.22));
  box-shadow: 0 30px 90px rgba(15,23,42,.32);
}

.spt-sheet-head {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
  padding-bottom: 12px;
}

.spt-sheet-head h2 {
  margin: 0;
  color: var(--text, #0f172a);
  font-size: 21px;
  font-weight: 1000;
  letter-spacing: -.05em;
}

.spt-sheet-head p {
  margin: 5px 0 0;
  color: var(--muted, #64748b);
  font-size: 12px;
  line-height: 1.5;
  font-weight: 750;
}

.spt-sheet-head button {
  width: 38px;
  height: 38px;
  border: 1px solid var(--border, rgba(148,163,184,.22));
  border-radius: 999px;
  background: var(--surface, #fff);
  color: var(--text, #0f172a);
  font-weight: 1000;
  cursor: pointer;
  flex: 0 0 auto;
}

.spt-menu-list {
  display: grid;
  gap: 8px;
}

.spt-menu-list button {
  width: 100%;
  display: grid;
  grid-template-columns: 42px minmax(0, 1fr);
  column-gap: 10px;
  align-items: center;
  min-height: 58px;
  border: 1px solid var(--border, rgba(148,163,184,.22));
  border-radius: 18px;
  padding: 9px;
  background: var(--surface, #fff);
  color: var(--text, #0f172a);
  text-align: left;
  cursor: pointer;
}

.spt-menu-list button span {
  grid-row: span 2;
  width: 42px;
  height: 42px;
  display: grid;
  place-items: center;
  border-radius: 16px;
  background: color-mix(in srgb, var(--spt-primary, var(--primary-color, #2563eb)) 10%, transparent);
  color: var(--spt-primary, var(--primary-color, #2563eb));
  font-weight: 1000;
}

.spt-menu-list button b,
.spt-menu-list button small {
  display: block;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.spt-menu-list button b {
  font-size: 13px;
  font-weight: 1000;
}

.spt-menu-list button small {
  margin-top: 2px;
  color: var(--muted, #64748b);
  font-size: 11px;
  font-weight: 750;
}

.spt-preview-scroll {
  width: 100%;
  max-width: 100%;
  min-width: 0;
  overflow-x: auto;
  overflow-y: visible;
  -webkit-overflow-scrolling: touch;
  padding: 8px;
  border-radius: 22px;
  background: color-mix(in srgb, var(--muted, #64748b) 8%, transparent);
  border: 1px solid var(--border, rgba(148,163,184,.18));
}

.spt-preview-scale {
  width: max-content;
  min-width: 100%;
  transform-origin: top left;
}

.spt-summary-print-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 6px;
  margin-bottom: 12px;
}

.spt-summary-print-grid > div {
  min-width: 0;
  overflow: hidden;
}

.spt-summary-label {
  display: block;
  max-width: 100%;
  font-size: 8px;
  line-height: 1.15;
  opacity: 0.72;
  font-weight: 900;
  white-space: normal;
  overflow-wrap: anywhere;
  word-break: break-word;
}

.spt-summary-value {
  margin-top: 3px;
  font-size: 18px;
  line-height: 1;
  font-weight: 900;
}

.spt-print-timeline {
  border-left: 4px solid;
  padding-left: 14px;
  display: grid;
  gap: 10px;
  margin-bottom: 14px;
}

.spt-print-card {
  position: relative;
  border: 1px solid #ddd;
  border-radius: 14px;
  padding: 10px;
  break-inside: avoid;
}

.spt-print-dot {
  position: absolute;
  left: -25px;
  top: 14px;
  width: 18px;
  height: 18px;
  border-radius: 999px;
  border: 3px solid #fff;
  box-shadow: 0 0 0 1px #ddd;
}

.spt-print-card-head {
  display: none;
}

.spt-card-layout {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 10px;
  align-items: start;
}

.spt-title {
  font-size: 11.5px;
  font-weight: 900;
  overflow-wrap: anywhere;
}

.spt-period-line {
  margin-top: 4px;
  font-size: 9.5px;
  opacity: 0.78;
  font-weight: 650;
  overflow-wrap: anywhere;
}

.spt-note {
  margin-top: 6px;
  font-size: 9.5px;
  line-height: 1.35;
  overflow-wrap: anywhere;
}

.spt-decision-pill {
  min-width: 90px;
  text-align: center;
  border-radius: 999px;
  padding: 6px 10px;
  background: #fff;
  border: 1px solid;
  font-weight: 900;
  font-size: 9.5px;
}

.spt-mini-grid {
  margin-top: 8px;
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 6px;
  font-size: 9px;
}

.spt-mini-grid div {
  min-width: 0;
  overflow-wrap: anywhere;
}

.spt-empty-box {
  padding: 20px;
  border: 1px dashed #bbb;
  border-radius: 12px;
  text-align: center;
  font-weight: 700;
}

.spt-table-wrap {
  width: 100%;
  max-width: 100%;
  overflow-x: auto;
}

.spt-footer {
  margin-top: 10px;
  border-top: 2px solid;
  padding-top: 5px;
  display: flex;
  justify-content: space-between;
  gap: 10px;
  font-size: 8.5px;
  color: #555;
}

@media screen and (max-width: 720px) {
  .spt-summary-print-grid {
    gap: 4px;
  }

  .spt-summary-print-grid > div {
    padding: 6px !important;
    border-radius: 9px !important;
  }

  .spt-summary-label {
    font-size: 6.8px;
    letter-spacing: -0.15px;
  }

  .spt-summary-value {
    font-size: 14px;
  }

  .spt-toolbar {
    display: grid;
  }

  .spt-screen-chips {
    display: flex;
  }

  .spt-shell:not(.expanded) .spt-preview-scroll {
    overflow: hidden;
    max-height: 82vh;
  }

  .spt-shell:not(.expanded) .spt-preview-scale {
    width: 210mm;
    transform: scale(calc((100vw - 28px) / 793.7008));
    transform-origin: top left;
  }

  .spt-shell:not(.expanded) .spt-preview-scroll::after {
    content: "";
    display: block;
    height: calc(1122.5197px * ((100vw - 28px) / 793.7008));
  }

  .spt-shell.expanded .spt-preview-scroll {
    overflow-x: auto;
    max-height: none;
  }

  .spt-shell.expanded .spt-preview-scale {
    transform: none;
  }

  .spt-print-card-head {
    display: inline-flex;
    margin-bottom: 8px;
    border: 0;
    border-radius: 999px;
    padding: 5px 9px;
    background: rgba(255,255,255,.72);
    color: #111827;
    font-size: 9px;
    font-weight: 900;
  }

  .spt-card-layout {
    grid-template-columns: minmax(0, 1fr);
  }

  .spt-decision-pill {
    width: fit-content;
    min-width: 0;
  }

  .spt-note:not(.open) {
    display: none;
  }

  .spt-mini-grid {
    grid-template-columns: minmax(0, 1fr);
  }
}

@media print {
  .spt-shell,
  .spt-preview-scroll,
  .spt-preview-scale {
    display: contents !important;
    transform: none !important;
    overflow: visible !important;
    padding: 0 !important;
    border: 0 !important;
    background: transparent !important;
  }

  .spt-toolbar,
  .spt-screen-chips,
  .spt-sheet-backdrop,
  .spt-print-card-head {
    display: none !important;
  }

  .spt-note {
    display: block !important;
  }
}
`;
